PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?founder ?founderLabel
WHERE {
  ?company wdt:P31 wd:Q4860228 ;
           wdt:P2013 ?revenue ;
           wdt:P571 ?foundingDate .
  ?company wdt:P112 ?founder .
  ?founder wdt:P569 ?birthDate .
  FILTER ( (YEAR(?foundingDate) - YEAR(?birthDate)) < 30 )
  OPTIONAL { ?founder rdfs:label ?founderLabel }
}
ORDER BY DESC(?revenue)
LIMIT 10

